#include<bits/stdc++.h>
#define rep(a,b,c) for(int c(a);c<=(b);++c)
#define drep(a,b,c) for(int c(a);c>=(b);--c)
using namespace std;
const int N=1010,INF=0x3f3f3f3f;char s[N];int k,a[N][26],n,dp[N][26],w[N];
int main()
{
	int T;scanf("%d",&T);
	Begin:
	
	scanf("%d%s",&k,s);int len=strlen(s);n=len/k;
	memset(a,0,sizeof(a));for(int i=0;i<len;++i){++a[i/k+1][s[i]-'a'];}
	memset(w,0,sizeof(w));rep(1,n,i){rep(0,25,j)if(a[i][j])++w[i];}
	memset(dp,0x3f,sizeof(dp));
	rep(0,25,j){if(a[1][j]>0)dp[1][j]=w[1];}
	rep(2,n,i)
	{
		rep(0,25,ed)if(a[i][ed]>0)
		{
			rep(0,25,j)
			{
				if(j==ed){dp[i][ed]=min(dp[i][ed],dp[i-1][j]+w[i]-(w[i]==1));}
				else dp[i][ed]=min(dp[i][ed],dp[i-1][j]+w[i]-(a[i][j]>0));
			}
		}
	}
	int ans=INF;rep(0,25,j)ans=min(ans,dp[n][j]);printf("%d\n",ans);
	
	
	if(--T)goto Begin;
}
